  ('social-worker-moex-04908', 'social-worker', 'social-worker-moex-108-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究者經過一段時間對 A 城市的觀察後，發現不同年齡、職業、以及宗教信仰的市民，對於各 政黨的市長候選人有相當歧異的看法。該研究者擬針對此觀察心得提出一項研究，進一步了解這', '["年齡對宗教信仰有 影響，因此影響投票行為", "宗教信仰會影響投票行為", "年齡會影響宗教信仰，進而影響投票 行為", "年齡與職業對投票行為有交互作用的影響"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "00b091c10e58", "answer_pdf_sha1": "fa23129d5204", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
